#!/usr/bin/env node
// MIPS32r2 (little-endian, o32) userspace interpreter for doomgeneric_mips.
// Loads the ELF, runs it, and services the x86_64-numbered syscalls that the
// custom libc (my_stdlib.c) emits via the MIPS `syscall` instruction.
//
//   syscall ABI (see my_stdlib.c syscall6 / exit):
//     v0 ($2) = syscall number (x86_64 numbering)
//     a0..a3 ($4..$7), t0 ($8), t1 ($9) = args 1..6
//     return value in v0 ; negative == -errno
//
// Usage:  node vm.js
// Reads doom.wad from this script's directory and writes frames to /tmp/frame.bmp

'use strict';
const fs = require('fs');
const path = require('path');

const BASE_DIR = __dirname;
const ELF_PATH = path.join(BASE_DIR, 'doomgeneric_mips');

// ---------------------------------------------------------------------------
// ELF loading
// ---------------------------------------------------------------------------
const BASE = 0x00400000;            // lowest virtual address of the image
const STACK_SIZE = 8 * 1024 * 1024; // guest stack, placed above the image

function loadElf(file) {
  const buf = fs.readFileSync(file);
  if (buf.readUInt32LE(0) !== 0x464c457f) throw new Error('not an ELF');
  const entry = buf.readUInt32LE(0x18);
  const phoff = buf.readUInt32LE(0x1c);
  const phentsize = buf.readUInt16LE(0x2a);
  const phnum = buf.readUInt16LE(0x2c);

  const segs = [];
  let maxAddr = BASE;
  for (let i = 0; i < phnum; i++) {
    const o = phoff + i * phentsize;
    const type = buf.readUInt32LE(o);
    if (type !== 1) continue; // PT_LOAD
    const offset = buf.readUInt32LE(o + 4);
    const vaddr = buf.readUInt32LE(o + 8);
    const filesz = buf.readUInt32LE(o + 16);
    const memsz = buf.readUInt32LE(o + 20);
    segs.push({ offset, vaddr, filesz, memsz });
    if (vaddr + memsz > maxAddr) maxAddr = vaddr + memsz;
  }

  // Total guest span: [BASE, maxAddr) rounded up, plus a stack region.
  const imageLen = ((maxAddr - BASE) + 0xffff) & ~0xffff;
  const memLen = imageLen + STACK_SIZE;
  const mem = new Uint8Array(memLen);
  for (const s of segs) {
    const dst = s.vaddr - BASE;
    buf.copy(mem, dst, s.offset, s.offset + s.filesz);
  }
  return { entry, mem, memLen };
}

const { entry, mem, memLen } = loadElf(ELF_PATH);
const dv = new DataView(mem.buffer);
const MEM_END = BASE + memLen;

function bad(addr, pc) {
  throw new Error('memory access out of range: addr=0x' + (addr >>> 0).toString(16) +
    ' pc=0x' + (pc >>> 0).toString(16));
}

// Memory helpers (little-endian). idx = addr - BASE.
function l8u(a) { const i = a - BASE; if (i < 0 || i >= memLen) bad(a, PC); return mem[i]; }
function l8s(a) { return (l8u(a) << 24) >> 24; }
function l16u(a) { const i = a - BASE; if (i < 0 || i + 1 >= memLen) bad(a, PC); return dv.getUint16(i, true); }
function l16s(a) { const i = a - BASE; if (i < 0 || i + 1 >= memLen) bad(a, PC); return dv.getInt16(i, true); }
function l32(a) { const i = a - BASE; if (i < 0 || i + 3 >= memLen) bad(a, PC); return dv.getInt32(i, true); }
function s8(a, v) { const i = a - BASE; if (i < 0 || i >= memLen) bad(a, PC); mem[i] = v & 0xff; }
function s16(a, v) { const i = a - BASE; if (i < 0 || i + 1 >= memLen) bad(a, PC); dv.setUint16(i, v & 0xffff, true); }
function s32(a, v) { const i = a - BASE; if (i < 0 || i + 3 >= memLen) bad(a, PC); dv.setInt32(i, v | 0, true); }

// ---------------------------------------------------------------------------
// CPU state
// ---------------------------------------------------------------------------
const reg = new Int32Array(32);
let HI = 0, LO = 0;
let PC = entry;
let nPC = (entry + 4) | 0;

// FP register file: 32 x 32-bit; doubles use even/odd pairs (FR=0, o32).
const fbuf = new ArrayBuffer(256);
const fdv = new DataView(fbuf);
let FCC = 0; // single condition code (cc0)
const getFW = (n) => fdv.getInt32(n * 4, true);
const setFW = (n, v) => fdv.setInt32(n * 4, v | 0, true);
const getF32 = (n) => fdv.getFloat32(n * 4, true);
const setF32 = (n, v) => fdv.setFloat32(n * 4, v, true);
const getF64 = (n) => fdv.getFloat64(n * 4, true);
const setF64 = (n, v) => fdv.setFloat64(n * 4, v, true);

