reg[25] = entry;                // t9 = entry (PIC convention)
reg[31] = 0;                    // ra

// ---------------------------------------------------------------------------
// Syscalls (x86_64 numbering as used by my_stdlib.c)
// ---------------------------------------------------------------------------
const SYS = {
  read: 0, write: 1, open: 2, close: 3, fstat: 5, lseek: 8,
  nanosleep: 35, exit: 60, exit_group: 231, fsync: 74, rename: 82,
  mkdir: 83, unlink: 87, gettimeofday: 96, time: 201,
};

class ExitException { constructor(code) { this.code = code; } }

const filePos = new Map(); // guest/host fd -> current offset

function readCString(addr) {
  let s = '';
  for (;;) {
    const c = l8u(addr++);
    if (c === 0) break;
    s += String.fromCharCode(c);
