  const a0 = reg[4], a1 = reg[5], a2 = reg[6];
  switch (num) {
    case SYS.write: {
      const fd = a0 | 0, addr = a1 >>> 0, count = a2 >>> 0;
      const idx = addr - BASE;
      if (idx < 0 || idx + count > memLen) return -14; // EFAULT
      const view = Buffer.from(mem.buffer, idx, count);
      try {
        const n = fs.writeSync(fd, view, 0, count, filePos.has(fd) ? filePos.get(fd) : null);
        if (filePos.has(fd)) filePos.set(fd, filePos.get(fd) + n);
        return n;
      } catch (e) { return errnoFrom(e); }
    }
    case SYS.read: {
      const fd = a0 | 0, addr = a1 >>> 0, count = a2 >>> 0;
      if (fd === 0) return 0; // stdin EOF
      const idx = addr - BASE;
      if (idx < 0 || idx + count > memLen) return -14;
      const view = Buffer.from(mem.buffer, idx, count);
      try {
        const pos = filePos.has(fd) ? filePos.get(fd) : 0;
        const n = fs.readSync(fd, view, 0, count, pos);
        filePos.set(fd, pos + n);
        return n;
      } catch (e) { return errnoFrom(e); }
    }
    case SYS.open: {
      const p = resolvePath(readCString(a0 >>> 0));
      const flags = a1 | 0;
      const mode = a2 >>> 0;
      try {
        const fd = fs.openSync(p, flags, mode || 0o644);
        filePos.set(fd, 0);
        return fd;
      } catch (e) { return errnoFrom(e); }
    }
    case SYS.close: {
      const fd = a0 | 0;
      if (fd <= 2) return 0;
      filePos.delete(fd);
      try { fs.closeSync(fd); return 0; } catch (e) { return errnoFrom(e); }
    }
    case SYS.lseek: {
      const fd = a0 | 0, off = a1 | 0, whence = a2 | 0;
      let base = 0;
      try {
        if (whence === 0) base = 0;
        else if (whence === 1) base = filePos.has(fd) ? filePos.get(fd) : 0;
        else if (whence === 2) base = fs.fstatSync(fd).size;
        else return -22;
      } catch (e) { return errnoFrom(e); }
      const np = base + off;
      if (np < 0) return -22;
      filePos.set(fd, np);
      return np;
    }
    case SYS.fsync: {
      const fd = a0 | 0;
      try { fs.fsyncSync(fd); } catch (e) {}
      return 0;
    }
    case SYS.unlink: {
      try { fs.unlinkSync(resolvePath(readCString(a0 >>> 0))); return 0; } catch (e) { return errnoFrom(e); }
    }
    case SYS.rename: {
      try { fs.renameSync(resolvePath(readCString(a0 >>> 0)), resolvePath(readCString(a1 >>> 0))); return 0; }
      catch (e) { return errnoFrom(e); }
    }
    case SYS.mkdir: {
      try { fs.mkdirSync(resolvePath(readCString(a0 >>> 0)), a1 >>> 0); return 0; } catch (e) { return errnoFrom(e); }
    }
    case SYS.time: {
      const t = Math.floor(Date.now() / 1000);
      if ((a0 >>> 0) !== 0) s32(a0 >>> 0, t);
      return t;
    }
    case SYS.gettimeofday: {
      if ((a0 >>> 0) !== 0) {
