}

// ---------------------------------------------------------------------------
// Unaligned load/store (little-endian) helpers for LWL/LWR/SWL/SWR
// ---------------------------------------------------------------------------
function lwl(addr, old) {
  const b = addr & 3;
  let r = old;
  for (let i = 0; i <= b; i++) {
    const pos = 3 - i;
    r = (r & ~(0xff << (pos * 8))) | (l8u(addr - i) << (pos * 8));
  }
  return r | 0;
}
function lwr(addr, old) {
  const b = addr & 3;
  let r = old;
  for (let i = 0; i <= 3 - b; i++) {
    const pos = i;
    r = (r & ~(0xff << (pos * 8))) | (l8u(addr + i) << (pos * 8));
  }
