      reg[ft] = getFW(fs); return;
    case 0x04: // MTC1
      setFW(fs, reg[ft]); return;
    case 0x03: // MFHC1
      reg[ft] = getFW(fs + 1); return;
    case 0x07: // MTHC1
      setFW(fs + 1, reg[ft]); return;
    case 0x08: { // BC1F / BC1T
      const tf = (inst >> 16) & 1;
      const off = ((inst << 16) >> 16) << 2;
      if ((FCC & 1) === tf) nPC = (PC + off) | 0;
      return;
