    case 0x10: { // single (.s)
      switch (funct) {
        case 0x00: setF32(fd, getF32(fs) + getF32(ft)); return;
        case 0x01: setF32(fd, getF32(fs) - getF32(ft)); return;
        case 0x02: setF32(fd, getF32(fs) * getF32(ft)); return;
        case 0x03: setF32(fd, getF32(fs) / getF32(ft)); return;
