        case 0x0d: { let t = Math.trunc(getF32(fs)); setFW(fd, t | 0); return; }
        case 0x11: { const tf = (inst >> 16) & 1; if ((FCC & 1) === tf) setF32(fd, getF32(fs)); return; }
        case 0x20: setF32(fd, getF32(fs)); return; // cvt.s.s (nop-ish)
        case 0x21: setF64(fd, getF32(fs)); return; // cvt.d.s
        case 0x24: setFW(fd, Math.round(getF32(fs)) | 0); return; // cvt.w.s
        default:
          if ((funct & 0x30) === 0x30) { // c.cond.s
            const a = getF32(fs), b = getF32(ft);
            FCC = fcompare(funct, a, b) ? 1 : 0; return;
          }
          throw new Error('unhandled cop1.s funct 0x' + funct.toString(16) + ' pc=0x' + (PC >>> 0).toString(16));
      }
    }
    case 0x11: { // double (.d)
      switch (funct) {
        case 0x00: setF64(fd, getF64(fs) + getF64(ft)); return;
        case 0x01: setF64(fd, getF64(fs) - getF64(ft)); return;
        case 0x02: setF64(fd, getF64(fs) * getF64(ft)); return;
        case 0x03: setF64(fd, getF64(fs) / getF64(ft)); return;
        case 0x04: setF64(fd, Math.sqrt(getF64(fs))); return;
        case 0x05: setF64(fd, Math.abs(getF64(fs))); return;
        case 0x06: setF64(fd, getF64(fs)); return;
        case 0x07: setF64(fd, -getF64(fs)); return;
        case 0x0d: { let t = Math.trunc(getF64(fs)); setFW(fd, t | 0); return; }
        case 0x11: { const tf = (inst >> 16) & 1; if ((FCC & 1) === tf) setF64(fd, getF64(fs)); return; }
        case 0x20: setF32(fd, getF64(fs)); return; // cvt.s.d
        case 0x24: setFW(fd, Math.round(getF64(fs)) | 0); return; // cvt.w.d
        default:
          if ((funct & 0x30) === 0x30) {
            const a = getF64(fs), b = getF64(ft);
            FCC = fcompare(funct, a, b) ? 1 : 0; return;
          }
          throw new Error('unhandled cop1.d funct 0x' + funct.toString(16) + ' pc=0x' + (PC >>> 0).toString(16));
      }
    }
    case 0x14: { // word -> fp
      switch (funct) {
        case 0x20: setF32(fd, getFW(fs)); return; // cvt.s.w
        case 0x21: setF64(fd, getFW(fs)); return; // cvt.d.w
        default: throw new Error('unhandled cop1.w funct 0x' + funct.toString(16));
      }
    }
    default:
      throw new Error('unhandled cop1 rs 0x' + rs.toString(16) + ' pc=0x' + (PC >>> 0).toString(16));
  }
}

function fcompare(funct, a, b) {
  // MIPS c.cond: condition bits in funct low nibble.
  const cond = funct & 0xf;
  const unord = (a !== a) || (b !== b); // NaN
  const lt = a < b, eq = a === b;
  switch (cond) {
    case 0x0: return false;               // F
    case 0x1: return unord;               // UN
    case 0x2: return eq;                   // EQ
    case 0x3: return unord || eq;          // UEQ
    case 0x4: return !unord && lt;         // OLT
    case 0x5: return unord || lt;          // ULT
    case 0x6: return !unord && (lt || eq); // OLE
    case 0x7: return unord || lt || eq;    // ULE
    default:                               // signalling variants: same predicate
      switch (cond) {
        case 0xc: return !unord && lt;
        case 0xe: return !unord && (lt || eq);
        case 0xa: return eq;
        default: return false;
      }
  }
}

// ---------------------------------------------------------------------------
// Main execution loop
// ---------------------------------------------------------------------------
function run() {
  for (;;) {
    reg[0] = 0;
    const inst = l32(PC) >>> 0;
    const curPC = PC;
    PC = nPC;
    nPC = (nPC + 4) | 0;

    const op = inst >>> 26;
    switch (op) {
      case 0x00: { // SPECIAL
        const funct = inst & 0x3f;
        const rs = (inst >> 21) & 31;
        const rt = (inst >> 16) & 31;
        const rd = (inst >> 11) & 31;
        const sa = (inst >> 6) & 31;
        switch (funct) {
          case 0x00: if (rd) reg[rd] = reg[rt] << sa; break; // sll
          case 0x02: // srl / rotr
            if (rd) reg[rd] = (inst & (1 << 21)) ? (sa === 0 ? reg[rt] : ((reg[rt] >>> sa) | (reg[rt] << (32 - sa)))) : (reg[rt] >>> sa);
            break;
          case 0x03: if (rd) reg[rd] = reg[rt] >> sa; break; // sra
          case 0x04: if (rd) reg[rd] = reg[rt] << (reg[rs] & 31); break; // sllv
          case 0x06: { // srlv / rotrv
            const sh = reg[rs] & 31;
            if (rd) reg[rd] = (inst & (1 << 6)) ? (sh === 0 ? reg[rt] : ((reg[rt] >>> sh) | (reg[rt] << (32 - sh)))) : (reg[rt] >>> sh);
            break;
          }
          case 0x07: if (rd) reg[rd] = reg[rt] >> (reg[rs] & 31); break; // srav
          case 0x08: nPC = reg[rs] | 0; break; // jr
          case 0x09: { const t = reg[rs] | 0; if (rd) reg[rd] = nPC; nPC = t; break; } // jalr
          case 0x0a: if (reg[rt] === 0 && rd) reg[rd] = reg[rs]; break; // movz
          case 0x0b: if (reg[rt] !== 0 && rd) reg[rd] = reg[rs]; break; // movn
          case 0x0c: reg[2] = doSyscall() | 0; break; // syscall
          case 0x0d: throw new Error('break at pc=0x' + (curPC >>> 0).toString(16)); // break
          case 0x0f: break; // sync
          case 0x10: if (rd) reg[rd] = HI; break; // mfhi
          case 0x11: HI = reg[rs]; break; // mthi
          case 0x12: if (rd) reg[rd] = LO; break; // mflo
          case 0x13: LO = reg[rs]; break; // mtlo
          case 0x18: { // mult
            const p = BigInt(reg[rs]) * BigInt(reg[rt]);
            LO = Number(BigInt.asIntN(32, p)) | 0;
            HI = Number(BigInt.asIntN(32, p >> 32n)) | 0;
            break;
          }
          case 0x19: { // multu
            const p = BigInt(reg[rs] >>> 0) * BigInt(reg[rt] >>> 0);
            LO = Number(p & 0xffffffffn) | 0;
            HI = Number((p >> 32n) & 0xffffffffn) | 0;
            break;
          }
          case 0x1a: { // div
            const a = reg[rs] | 0, b = reg[rt] | 0;
            if (b === 0) { LO = 0; HI = 0; }
            else if (a === -2147483648 && b === -1) { LO = -2147483648; HI = 0; }
            else { LO = (a / b) | 0; HI = (a % b) | 0; }
            break;
          }
          case 0x1b: { // divu
            const a = reg[rs] >>> 0, b = reg[rt] >>> 0;
            if (b === 0) { LO = 0; HI = 0; }
            else { LO = (a / b) >>> 0; HI = (a % b) >>> 0; }
            break;
          }
          case 0x20: if (rd) reg[rd] = (reg[rs] + reg[rt]) | 0; break; // add
          case 0x21: if (rd) reg[rd] = (reg[rs] + reg[rt]) | 0; break; // addu
          case 0x22: if (rd) reg[rd] = (reg[rs] - reg[rt]) | 0; break; // sub
          case 0x23: if (rd) reg[rd] = (reg[rs] - reg[rt]) | 0; break; // subu
          case 0x24: if (rd) reg[rd] = reg[rs] & reg[rt]; break; // and
          case 0x25: if (rd) reg[rd] = reg[rs] | reg[rt]; break; // or
          case 0x26: if (rd) reg[rd] = reg[rs] ^ reg[rt]; break; // xor
          case 0x27: if (rd) reg[rd] = ~(reg[rs] | reg[rt]); break; // nor
          case 0x2a: if (rd) reg[rd] = (reg[rs] | 0) < (reg[rt] | 0) ? 1 : 0; break; // slt
          case 0x2b: if (rd) reg[rd] = (reg[rs] >>> 0) < (reg[rt] >>> 0) ? 1 : 0; break; // sltu
          case 0x30: case 0x31: case 0x32: case 0x33: case 0x36: break; // tge/tgeu/tlt/tltu/tne (no trap in normal run)
          case 0x34: if (reg[rs] === reg[rt]) throw new Error('teq trap at pc=0x' + (curPC >>> 0).toString(16)); break; // teq
          case 0x01: { // MOVCI (movf/movt on integer)
            const tf = (inst >> 16) & 1;
            if ((FCC & 1) === tf && rd) reg[rd] = reg[rs];
            break;
          }
          default:
            throw new Error('unhandled SPECIAL funct 0x' + funct.toString(16) + ' pc=0x' + (curPC >>> 0).toString(16));
        }
        break;
      }
      case 0x01: { // REGIMM
        const rs = (inst >> 21) & 31;
        const rt = (inst >> 16) & 31;
        const off = ((inst << 16) >> 16) << 2;
        const v = reg[rs] | 0;
        switch (rt) {
          case 0x00: if (v < 0) nPC = (PC + off) | 0; break; // bltz
          case 0x01: if (v >= 0) nPC = (PC + off) | 0; break; // bgez
          case 0x10: reg[31] = nPC; if (v < 0) nPC = (PC + off) | 0; break; // bltzal
          case 0x11: reg[31] = nPC; if (v >= 0) nPC = (PC + off) | 0; break; // bgezal
          default: throw new Error('unhandled REGIMM rt 0x' + rt.toString(16));
        }
        break;
      }
      case 0x02: nPC = ((PC & 0xf0000000) | ((inst & 0x03ffffff) << 2)) | 0; break; // j
      case 0x03: reg[31] = nPC; nPC = ((PC & 0xf0000000) | ((inst & 0x03ffffff) << 2)) | 0; break; // jal
      case 0x04: { const rs = (inst >> 21) & 31, rt = (inst >> 16) & 31; if (reg[rs] === reg[rt]) nPC = (PC + (((inst << 16) >> 16) << 2)) | 0; break; } // beq
      case 0x05: { const rs = (inst >> 21) & 31, rt = (inst >> 16) & 31; if (reg[rs] !== reg[rt]) nPC = (PC + (((inst << 16) >> 16) << 2)) | 0; break; } // bne
      case 0x06: { const rs = (inst >> 21) & 31; if ((reg[rs] | 0) <= 0) nPC = (PC + (((inst << 16) >> 16) << 2)) | 0; break; } // blez
      case 0x07: { const rs = (inst >> 21) & 31; if ((reg[rs] | 0) > 0) nPC = (PC + (((inst << 16) >> 16) << 2)) | 0; break; } // bgtz
      case 0x08: { const rt = (inst >> 16) & 31, rs = (inst >> 21) & 31; if (rt) reg[rt] = (reg[rs] + ((inst << 16) >> 16)) | 0; break; } // addi
      case 0x09: { const rt = (inst >> 16) & 31, rs = (inst >> 21) & 31; if (rt) reg[rt] = (reg[rs] + ((inst << 16) >> 16)) | 0; break; } // addiu
      case 0x0a: { const rt = (inst >> 16) & 31, rs = (inst >> 21) & 31; if (rt) reg[rt] = (reg[rs] | 0) < ((inst << 16) >> 16) ? 1 : 0; break; } // slti
      case 0x0b: { const rt = (inst >> 16) & 31, rs = (inst >> 21) & 31; if (rt) reg[rt] = (reg[rs] >>> 0) < (((inst << 16) >> 16) >>> 0) ? 1 : 0; break; } // sltiu
      case 0x0c: { const rt = (inst >> 16) & 31, rs = (inst >> 21) & 31; if (rt) reg[rt] = reg[rs] & (inst & 0xffff); break; } // andi
      case 0x0d: { const rt = (inst >> 16) & 31, rs = (inst >> 21) & 31; if (rt) reg[rt] = reg[rs] | (inst & 0xffff); break; } // ori
      case 0x0e: { const rt = (inst >> 16) & 31, rs = (inst >> 21) & 31; if (rt) reg[rt] = reg[rs] ^ (inst & 0xffff); break; } // xori
      case 0x0f: { const rt = (inst >> 16) & 31; if (rt) reg[rt] = (inst & 0xffff) << 16; break; } // lui
      case 0x11: execCop1(inst); break; // COP1
      case 0x1c: { // SPECIAL2
        const funct = inst & 0x3f;
        const rs = (inst >> 21) & 31, rt = (inst >> 16) & 31, rd = (inst >> 11) & 31;
        switch (funct) {
          case 0x02: if (rd) reg[rd] = Math.imul(reg[rs], reg[rt]); break; // mul
          case 0x00: { // madd
            const p = BigInt(reg[rs]) * BigInt(reg[rt]) + ((BigInt(HI) << 32n) | BigInt(LO >>> 0));
            LO = Number(BigInt.asIntN(32, p)) | 0; HI = Number(BigInt.asIntN(32, p >> 32n)) | 0; break;
          }
          case 0x04: { // msub
            const p = ((BigInt(HI) << 32n) | BigInt(LO >>> 0)) - BigInt(reg[rs]) * BigInt(reg[rt]);
            LO = Number(BigInt.asIntN(32, p)) | 0; HI = Number(BigInt.asIntN(32, p >> 32n)) | 0; break;
          }
          case 0x20: { let x = reg[rs] >>> 0, n = 0; while (n < 32 && (x & 0x80000000) === 0) { x <<= 1; n++; } if (rd) reg[rd] = n; break; } // clz
          case 0x21: { let x = ~reg[rs] >>> 0, n = 0; while (n < 32 && (x & 0x80000000) === 0) { x <<= 1; n++; } if (rd) reg[rd] = n; break; } // clo
          default: throw new Error('unhandled SPECIAL2 funct 0x' + funct.toString(16) + ' pc=0x' + (curPC >>> 0).toString(16));
        }
        break;
      }
      case 0x1f: { // SPECIAL3
        const funct = inst & 0x3f;
        const rs = (inst >> 21) & 31, rt = (inst >> 16) & 31, rd = (inst >> 11) & 31, sa = (inst >> 6) & 31;
        switch (funct) {
          case 0x00: { // ext
            const pos = sa, size = rd + 1;
            const mask = size >= 32 ? 0xffffffff : ((1 << size) - 1);
            if (rt) reg[rt] = (reg[rs] >>> pos) & mask;
            break;
          }
          case 0x04: { // ins
            const pos = sa, size = rd - sa + 1;
            const mask = size >= 32 ? 0xffffffff : ((1 << size) - 1);
            const m = mask << pos;
            if (rt) reg[rt] = ((reg[rt] & ~m) | ((reg[rs] & mask) << pos)) | 0;
            break;
          }
          case 0x20: { // BSHFL
            const x = reg[rt];
            let r;
            if (sa === 0x02) r = (((x & 0xff00ff00) >>> 8) | ((x & 0x00ff00ff) << 8)) | 0; // wsbh
            else if (sa === 0x10) r = (x << 24) >> 24; // seb
            else if (sa === 0x18) r = (x << 16) >> 16; // seh
            else throw new Error('unhandled BSHFL sa 0x' + sa.toString(16));
            if (rd) reg[rd] = r;
            break;
          }
          default: throw new Error('unhandled SPECIAL3 funct 0x' + funct.toString(16) + ' pc=0x' + (curPC >>> 0).toString(16));
        }
        break;
      }
      // Loads / stores
      case 0x20: { const rt = (inst >> 16) & 31, rs = (inst >> 21) & 31; const a = (reg[rs] + ((inst << 16) >> 16)) | 0; if (rt) reg[rt] = l8s(a); break; } // lb
      case 0x21: { const rt = (inst >> 16) & 31, rs = (inst >> 21) & 31; const a = (reg[rs] + ((inst << 16) >> 16)) | 0; if (rt) reg[rt] = l16s(a); break; } // lh
      case 0x22: { const rt = (inst >> 16) & 31, rs = (inst >> 21) & 31; const a = (reg[rs] + ((inst << 16) >> 16)) | 0; const v = lwl(a, reg[rt]); if (rt) reg[rt] = v; break; } // lwl
      case 0x23: { const rt = (inst >> 16) & 31, rs = (inst >> 21) & 31; const a = (reg[rs] + ((inst << 16) >> 16)) | 0; if (rt) reg[rt] = l32(a); break; } // lw
      case 0x24: { const rt = (inst >> 16) & 31, rs = (inst >> 21) & 31; const a = (reg[rs] + ((inst << 16) >> 16)) | 0; if (rt) reg[rt] = l8u(a); break; } // lbu
      case 0x25: { const rt = (inst >> 16) & 31, rs = (inst >> 21) & 31; const a = (reg[rs] + ((inst << 16) >> 16)) | 0; if (rt) reg[rt] = l16u(a); break; } // lhu
      case 0x26: { const rt = (inst >> 16) & 31, rs = (inst >> 21) & 31; const a = (reg[rs] + ((inst << 16) >> 16)) | 0; const v = lwr(a, reg[rt]); if (rt) reg[rt] = v; break; } // lwr
      case 0x28: { const rt = (inst >> 16) & 31, rs = (inst >> 21) & 31; const a = (reg[rs] + ((inst << 16) >> 16)) | 0; s8(a, reg[rt]); break; } // sb
      case 0x29: { const rt = (inst >> 16) & 31, rs = (inst >> 21) & 31; const a = (reg[rs] + ((inst << 16) >> 16)) | 0; s16(a, reg[rt]); break; } // sh
      case 0x2a: { const rt = (inst >> 16) & 31, rs = (inst >> 21) & 31; const a = (reg[rs] + ((inst << 16) >> 16)) | 0; swl(a, reg[rt]); break; } // swl
      case 0x2b: { const rt = (inst >> 16) & 31, rs = (inst >> 21) & 31; const a = (reg[rs] + ((inst << 16) >> 16)) | 0; s32(a, reg[rt]); break; } // sw
      case 0x2e: { const rt = (inst >> 16) & 31, rs = (inst >> 21) & 31; const a = (reg[rs] + ((inst << 16) >> 16)) | 0; swr(a, reg[rt]); break; } // swr
      case 0x31: { const ft = (inst >> 16) & 31, rs = (inst >> 21) & 31; const a = (reg[rs] + ((inst << 16) >> 16)) | 0; setFW(ft, l32(a)); break; } // lwc1
      case 0x39: { const ft = (inst >> 16) & 31, rs = (inst >> 21) & 31; const a = (reg[rs] + ((inst << 16) >> 16)) | 0; s32(a, getFW(ft)); break; } // swc1
      case 0x35: { const ft = (inst >> 16) & 31, rs = (inst >> 21) & 31; const a = (reg[rs] + ((inst << 16) >> 16)) | 0; setFW(ft, l32(a)); setFW(ft + 1, l32(a + 4)); break; } // ldc1
      case 0x3d: { const ft = (inst >> 16) & 31, rs = (inst >> 21) & 31; const a = (reg[rs] + ((inst << 16) >> 16)) | 0; s32(a, getFW(ft)); s32(a + 4, getFW(ft + 1)); break; } // sdc1
      default:
        throw new Error('unhandled opcode 0x' + op.toString(16) + ' inst=0x' + inst.toString(16) + ' pc=0x' + (curPC >>> 0).toString(16));
    }
  }
}

try {
  run();
} catch (e) {
  if (e instanceof ExitException) {
    process.exitCode = e.code & 0xff;
  } else {
    process.stderr.write('[vm] fatal: ' + (e && e.stack ? e.stack : e) + '\n');
    process.exitCode = 1;
  }
}

#!/usr/bin/env node
// MIPS32r2 (little-endian, o32) userspace interpreter for doomgeneric_mips.
// Loads the ELF, runs it, and services the x86_64-numbered syscalls that the
// custom libc (my_stdlib.c) emits via the MIPS `syscall` instruction.
//
//   syscall ABI (see my_stdlib.c syscall6 / exit):
//     v0 ($2) = syscall number (x86_64 numbering)
//     a0..a3 ($4..$7), t0 ($8), t1 ($9) = args 1..6
//     return value in v0 ; negative == -errno
//
// Usage:  node vm.js
// Reads doom.wad from this script's directory and writes frames to /tmp/frame.bmp

'use strict';
const fs = require('fs');
const path = require('path');

const BASE_DIR = __dirname;
const ELF_PATH = path.join(BASE_DIR, 'doomgeneric_mips');

// ---------------------------------------------------------------------------
// ELF loading
// ---------------------------------------------------------------------------
const BASE = 0x00400000;            // lowest virtual address of the image
const STACK_SIZE = 8 * 1024 * 1024; // guest stack, placed above the image

function loadElf(file) {
  const buf = fs.readFileSync(file);
  if (buf.readUInt32LE(0) !== 0x464c457f) throw new Error('not an ELF');
  const entry = buf.readUInt32LE(0x18);
  const phoff = buf.readUInt32LE(0x1c);
  const phentsize = buf.readUInt16LE(0x2a);
  const phnum = buf.readUInt16LE(0x2c);

  const segs = [];
  let maxAddr = BASE;
  for (let i = 0; i < phnum; i++) {
    const o = phoff + i * phentsize;
    const type = buf.readUInt32LE(o);
    if (type !== 1) continue; // PT_LOAD
    const offset = buf.readUInt32LE(o + 4);
    const vaddr = buf.readUInt32LE(o + 8);
    const filesz = buf.readUInt32LE(o + 16);
    const memsz = buf.readUInt32LE(o + 20);
    segs.push({ offset, vaddr, filesz, memsz });
    if (vaddr + memsz > maxAddr) maxAddr = vaddr + memsz;
  }

  // Total guest span: [BASE, maxAddr) rounded up, plus a stack region.
  const imageLen = ((maxAddr - BASE) + 0xffff) & ~0xffff;
  const memLen = imageLen + STACK_SIZE;
  const mem = new Uint8Array(memLen);
  for (const s of segs) {
    const dst = s.vaddr - BASE;
    buf.copy(mem, dst, s.offset, s.offset + s.filesz);
  }
  return { entry, mem, memLen };
}

const { entry, mem, memLen } = loadElf(ELF_PATH);
const dv = new DataView(mem.buffer);
const MEM_END = BASE + memLen;

function bad(addr, pc) {
  throw new Error('memory access out of range: addr=0x' + (addr >>> 0).toString(16) +
    ' pc=0x' + (pc >>> 0).toString(16));
}

// Memory helpers (little-endian). idx = addr - BASE.
function l8u(a) { const i = a - BASE; if (i < 0 || i >= memLen) bad(a, PC); return mem[i]; }
function l8s(a) { return (l8u(a) << 24) >> 24; }
function l16u(a) { const i = a - BASE; if (i < 0 || i + 1 >= memLen) bad(a, PC); return dv.getUint16(i, true); }
function l16s(a) { const i = a - BASE; if (i < 0 || i + 1 >= memLen) bad(a, PC); return dv.getInt16(i, true); }
function l32(a) { const i = a - BASE; if (i < 0 || i + 3 >= memLen) bad(a, PC); return dv.getInt32(i, true); }
function s8(a, v) { const i = a - BASE; if (i < 0 || i >= memLen) bad(a, PC); mem[i] = v & 0xff; }
function s16(a, v) { const i = a - BASE; if (i < 0 || i + 1 >= memLen) bad(a, PC); dv.setUint16(i, v & 0xffff, true); }
function s32(a, v) { const i = a - BASE; if (i < 0 || i + 3 >= memLen) bad(a, PC); dv.setInt32(i, v | 0, true); }

// ---------------------------------------------------------------------------
// CPU state
// ---------------------------------------------------------------------------
const reg = new Int32Array(32);
let HI = 0, LO = 0;
let PC = entry;
let nPC = (entry + 4) | 0;

// FP register file: 32 x 32-bit; doubles use even/odd pairs (FR=0, o32).
const fbuf = new ArrayBuffer(256);
const fdv = new DataView(fbuf);
let FCC = 0; // single condition code (cc0)
const getFW = (n) => fdv.getInt32(n * 4, true);
const setFW = (n, v) => fdv.setInt32(n * 4, v | 0, true);
const getF32 = (n) => fdv.getFloat32(n * 4, true);
const setF32 = (n, v) => fdv.setFloat32(n * 4, v, true);
const getF64 = (n) => fdv.getFloat64(n * 4, true);
const setF64 = (n, v) => fdv.setFloat64(n * 4, v, true);

// Initial register setup.
reg[29] = (MEM_END - 16) & ~15; // sp near top of stack region
reg[28] = 0x0047d090;           // gp (_gp), harmless under static model
reg[25] = entry;                // t9 = entry (PIC convention)
reg[31] = 0;                    // ra

// ---------------------------------------------------------------------------
// Syscalls (x86_64 numbering as used by my_stdlib.c)
// ---------------------------------------------------------------------------
const SYS = {
  read: 0, write: 1, open: 2, close: 3, fstat: 5, lseek: 8,
  nanosleep: 35, exit: 60, exit_group: 231, fsync: 74, rename: 82,
  mkdir: 83, unlink: 87, gettimeofday: 96, time: 201,
};

class ExitException { constructor(code) { this.code = code; } }

const filePos = new Map(); // guest/host fd -> current offset

function readCString(addr) {
  let s = '';
  for (;;) {
    const c = l8u(addr++);
    if (c === 0) break;
    s += String.fromCharCode(c);
  }
  return s;
}

function resolvePath(p) {
  if (p.startsWith('/')) return p;
  return path.join(BASE_DIR, p);
}

function errnoFrom(e) {
  if (typeof e.errno === 'number') return e.errno; // negative on Linux
  const map = { ENOENT: -2, EACCES: -13, EEXIST: -17, EISDIR: -21, ENOTDIR: -20, EINVAL: -22, EBADF: -9, ENOTEMPTY: -39 };
  return map[e.code] || -1;
}

function doSyscall() {
  const num = reg[2] >>> 0;
  const a0 = reg[4], a1 = reg[5], a2 = reg[6];
